import React, { useState, useEffect } from 'react';
import { api } from '../services/api';
import { useAuth } from '../context/AuthContext';

interface UserProfile {
  id: number;
  nombre: string;
  email: string;
  rol: string;
  created_at: string;
  avatar?: string;
}

interface ProfileFormData {
  nombre: string;
  email: string;
  currentPassword: string;
  newPassword: string;
  confirmPassword: string;
}

const UserProfile: React.FC = () => {
  const { user, updateUser } = useAuth();
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [activeTab, setActiveTab] = useState<'profile' | 'security' | 'preferences'>('profile');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  const [formData, setFormData] = useState<ProfileFormData>({
    nombre: '',
    email: '',
    currentPassword: '',
    newPassword: '',
    confirmPassword: ''
  });

  useEffect(() => {
    if (user) {
      setProfile(user);
      setFormData({
        nombre: user.nombre || '',
        email: user.email || '',
        currentPassword: '',
        newPassword: '',
        confirmPassword: ''
      });
    }
  }, [user]);

  const handleUpdateProfile = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);

    try {
      const response = await api.put(`/users/${user?.id}`, {
        nombre: formData.nombre,
        email: formData.email
      });

      setProfile(prev => prev ? { ...prev, nombre: formData.nombre, email: formData.email } : null);
      updateUser({ ...user!, nombre: formData.nombre, email: formData.email });
      setIsEditing(false);
      setMessage({ type: 'success', text: 'Perfil actualizado exitosamente' });
    } catch (error) {
      setMessage({ type: 'error', text: 'Error actualizando el perfil' });
    } finally {
      setLoading(false);
    }
  };

  const handleChangePassword = async (e: React.FormEvent) => {
    e.preventDefault();

    if (formData.newPassword !== formData.confirmPassword) {
      setMessage({ type: 'error', text: 'Las contraseñas no coinciden' });
      return;
    }

    if (formData.newPassword.length < 6) {
      setMessage({ type: 'error', text: 'La contraseña debe tener al menos 6 caracteres' });
      return;
    }

    setLoading(true);
    setMessage(null);

    try {
      await api.put(`/users/${user?.id}/password`, {
        currentPassword: formData.currentPassword,
        newPassword: formData.newPassword
      });

      setFormData(prev => ({ ...prev, currentPassword: '', newPassword: '', confirmPassword: '' }));
      setMessage({ type: 'success', text: 'Contraseña actualizada exitosamente' });
    } catch (error) {
      setMessage({ type: 'error', text: 'Error actualizando la contraseña' });
    } finally {
      setLoading(false);
    }
  };

  const getRoleIcon = (rol: string) => {
    const icons = {
      administrador: '👑',
      gerente: '📊',
      veterinario: '🩺',
      tecnico: '🔧',
      auxiliar: '👤'
    };
    return icons[rol as keyof typeof icons] || '👤';
  };

  const getRoleColor = (rol: string) => {
    const colors = {
      administrador: '#e74c3c',
      gerente: '#f39c12',
      veterinario: '#3498db',
      tecnico: '#27ae60',
      auxiliar: '#95a5a6'
    };
    return colors[rol as keyof typeof colors] || '#6c757d';
  };

  if (!profile) {
    return (
      <div className="loading">
        <div className="loading-spinner">🔄</div>
        <div>Cargando perfil...</div>
      </div>
    );
  }

  return (
    <div className="fade-in container" style={{ padding: '20px 0', maxWidth: '800px' }}>
      {/* Header del Perfil */}
      <div className="card mb-4">
        <div className="card-header" style={{ background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)' }}>
          <div className="d-flex align-center justify-between flex-wrap gap-2">
            <div className="d-flex align-center gap-3">
              <div style={{
                width: '80px',
                height: '80px',
                borderRadius: '50%',
                background: 'rgba(255,255,255,0.2)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: '32px',
                border: '3px solid rgba(255,255,255,0.3)'
              }}>
                {getRoleIcon(profile.rol)}
              </div>
              <div>
                <h1 className="card-title" style={{ margin: '0 0 8px 0' }}>
                  {profile.nombre}
                </h1>
                <div className="d-flex align-center gap-2 flex-wrap">
                  <span style={{
                    background: getRoleColor(profile.rol),
                    color: 'white',
                    padding: '4px 12px',
                    borderRadius: '20px',
                    fontSize: '12px',
                    fontWeight: '600',
                    textTransform: 'uppercase'
                  }}>
                    {profile.rol}
                  </span>
                  <span style={{ opacity: 0.9, fontSize: '14px' }}>
                    📧 {profile.email}
                  </span>
                </div>
              </div>
            </div>
            <button
              onClick={() => setIsEditing(!isEditing)}
              className="btn btn-sm"
              style={{ 
                background: 'rgba(255,255,255,0.2)', 
                color: 'white',
                border: '1px solid rgba(255,255,255,0.3)'
              }}
            >
              {isEditing ? '❌ Cancelar' : '✏️ Editar Perfil'}
            </button>
          </div>
        </div>
      </div>

      {/* Mensaje de Estado */}
      {message && (
        <div className={`alert alert-${message.type} mb-3`}>
          {message.type === 'success' ? '✅' : '❌'} {message.text}
        </div>
      )}

      {/* Tabs de Navegación */}
      <div className="tab-container mb-4">
        {[
          { key: 'profile', label: '👤 Información Personal', desc: 'Datos básicos' },
          { key: 'security', label: '🔒 Seguridad', desc: 'Contraseña' },
          { key: 'preferences', label: '⚙️ Preferencias', desc: 'Configuración' }
        ].map(tab => (
          <button
            key={tab.key}
            onClick={() => setActiveTab(tab.key as any)}
            className={`tab-button ${activeTab === tab.key ? 'active' : ''}`}
          >
            <div>{tab.label}</div>
            <div style={{ fontSize: '12px', opacity: 0.8, marginTop: '2px' }}>{tab.desc}</div>
          </button>
        ))}
      </div>

      {/* Contenido de Tabs */}
      <div className="card">
        <div style={{ padding: '25px' }}>
          {/* Tab: Información Personal */}
          {activeTab === 'profile' && (
            <div>
              <h3 className="mb-3">👤 Información Personal</h3>

              {isEditing ? (
                <form onSubmit={handleUpdateProfile}>
                  <div className="grid grid-2">
                    <div className="form-group">
                      <label className="form-label">Nombre Completo</label>
                      <input
                        type="text"
                        className="form-control"
                        value={formData.nombre}
                        onChange={(e) => setFormData(prev => ({ ...prev, nombre: e.target.value }))}
                        required
                      />
                    </div>
                    <div className="form-group">
                      <label className="form-label">Correo Electrónico</label>
                      <input
                        type="email"
                        className="form-control"
                        value={formData.email}
                        onChange={(e) => setFormData(prev => ({ ...prev, email: e.target.value }))}
                        required
                      />
                    </div>
                  </div>

                  <div className="d-flex gap-2 flex-wrap">
                    <button 
                      type="submit" 
                      className="btn btn-primary"
                      disabled={loading}
                    >
                      {loading ? '🔄 Guardando...' : '💾 Guardar Cambios'}
                    </button>
                    <button 
                      type="button" 
                      onClick={() => setIsEditing(false)}
                      className="btn"
                      style={{ background: '#6c757d', color: 'white' }}
                    >
                      ❌ Cancelar
                    </button>
                  </div>
                </form>
              ) : (
                <div className="grid grid-2">
                  <div>
                    <h5 style={{ color: 'var(--text-secondary)', marginBottom: '8px' }}>Nombre</h5>
                    <p style={{ fontSize: '16px', fontWeight: '600' }}>{profile.nombre}</p>
                  </div>
                  <div>
                    <h5 style={{ color: 'var(--text-secondary)', marginBottom: '8px' }}>Email</h5>
                    <p style={{ fontSize: '16px', fontWeight: '600' }}>{profile.email}</p>
                  </div>
                  <div>
                    <h5 style={{ color: 'var(--text-secondary)', marginBottom: '8px' }}>Rol</h5>
                    <div className="d-flex align-center gap-2">
                      <span>{getRoleIcon(profile.rol)}</span>
                      <span style={{ fontSize: '16px', fontWeight: '600', textTransform: 'capitalize' }}>
                        {profile.rol}
                      </span>
                    </div>
                  </div>
                  <div>
                    <h5 style={{ color: 'var(--text-secondary)', marginBottom: '8px' }}>Miembro desde</h5>
                    <p style={{ fontSize: '16px', fontWeight: '600' }}>
                      {new Date(profile.created_at).toLocaleDateString('es-ES', {
                        year: 'numeric',
                        month: 'long',
                        day: 'numeric'
                      })}
                    </p>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Tab: Seguridad */}
          {activeTab === 'security' && (
            <div>
              <h3 className="mb-3">🔒 Cambiar Contraseña</h3>

              <form onSubmit={handleChangePassword}>
                <div className="grid grid-2">
                  <div className="form-group">
                    <label className="form-label">Contraseña Actual</label>
                    <input
                      type="password"
                      className="form-control"
                      value={formData.currentPassword}
                      onChange={(e) => setFormData(prev => ({ ...prev, currentPassword: e.target.value }))}
                      required
                    />
                  </div>
                  <div></div>
                  <div className="form-group">
                    <label className="form-label">Nueva Contraseña</label>
                    <input
                      type="password"
                      className="form-control"
                      value={formData.newPassword}
                      onChange={(e) => setFormData(prev => ({ ...prev, newPassword: e.target.value }))}
                      minLength={6}
                      required
                    />
                    <small style={{ color: 'var(--text-muted)', fontSize: '12px' }}>
                      Mínimo 6 caracteres
                    </small>
                  </div>
                  <div className="form-group">
                    <label className="form-label">Confirmar Nueva Contraseña</label>
                    <input
                      type="password"
                      className="form-control"
                      value={formData.confirmPassword}
                      onChange={(e) => setFormData(prev => ({ ...prev, confirmPassword: e.target.value }))}
                      required
                    />
                  </div>
                </div>

                <button 
                  type="submit" 
                  className="btn btn-primary"
                  disabled={loading}
                >
                  {loading ? '🔄 Actualizando...' : '🔒 Cambiar Contraseña'}
                </button>
              </form>

              <div className="mt-4 p-3" style={{ background: 'var(--bg-light)', borderRadius: 'var(--border-radius)' }}>
                <h5 style={{ color: 'var(--text-primary)', marginBottom: '12px' }}>💡 Consejos de Seguridad</h5>
                <ul style={{ margin: 0, paddingLeft: '20px', color: 'var(--text-secondary)' }}>
                  <li>Use una contraseña única y segura</li>
                  <li>Combine letras, números y símbolos</li>
                  <li>No comparta sus credenciales</li>
                  <li>Cambie su contraseña regularmente</li>
                </ul>
              </div>
            </div>
          )}

          {/* Tab: Preferencias */}
          {activeTab === 'preferences' && (
            <div>
              <h3 className="mb-3">⚙️ Preferencias del Sistema</h3>

              <div className="grid grid-2">
                <div className="form-group">
                  <label className="form-label">Idioma</label>
                  <select className="form-control">
                    <option value="es">🇪🇸 Español</option>
                    <option value="en">🇺🇸 English</option>
                  </select>
                </div>
                <div className="form-group">
                  <label className="form-label">Zona Horaria</label>
                  <select className="form-control">
                    <option value="America/Bogota">🇨🇴 Bogotá (GMT-5)</option>
                    <option value="America/Mexico_City">🇲🇽 Ciudad de México (GMT-6)</option>
                    <option value="America/Lima">🇵🇪 Lima (GMT-5)</option>
                  </select>
                </div>
              </div>

              <div className="form-group">
                <label className="form-label">Notificaciones</label>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                  {[
                    { key: 'email', label: '📧 Notificaciones por Email', desc: 'Recibir alertas importantes por correo' },
                    { key: 'push', label: '🔔 Notificaciones Push', desc: 'Alertas en tiempo real en el navegador' },
                    { key: 'reports', label: '📊 Reportes Automáticos', desc: 'Recibir reportes semanales y mensuales' }
                  ].map(option => (
                    <label key={option.key} className="d-flex align-center gap-3" style={{ cursor: 'pointer' }}>
                      <input type="checkbox" defaultChecked style={{ transform: 'scale(1.2)' }} />
                      <div>
                        <div style={{ fontWeight: '600' }}>{option.label}</div>
                        <div style={{ fontSize: '14px', color: 'var(--text-muted)' }}>{option.desc}</div>
                      </div>
                    </label>
                  ))}
                </div>
              </div>

              <button className="btn btn-primary">
                💾 Guardar Preferencias
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default UserProfile;
